import re, torch

SYSTEM_PROMPT = (
    "You are a mathematical reasoning assistant. "
    "Think through the problem carefully inside <think>...</think> tags, "
    "then provide your final answer inside <answer>...</answer> tags. "
    "The answer should be a single number or expression."
)

def extract_think(text):
    m = re.search(r"<think>(.*?)</think>", text, re.DOTALL)
    return m.group(1).strip() if m else None

def extract_answer(text):
    m = re.search(r"<answer>(.*?)</answer>", text, re.DOTALL)
    return m.group(1).strip() if m else None

def accuracy_reward(completion, ground_truth):
    ans = extract_answer(completion)
    if ans is None:
        return 0.0
    def norm(s):
        s = s.strip().lower().replace(" ", "")
        try:
            return str(float(s))
        except ValueError:
            return s
    return 1.0 if norm(ans) == norm(ground_truth) else 0.0

def format_reward(completion):
    has_think  = bool(re.search(r"<think>.*?</think>",   completion, re.DOTALL))
    has_answer = bool(re.search(r"<answer>.*?</answer>", completion, re.DOTALL))
    return 0.5 * float(has_think) + 0.5 * float(has_answer)

def combined_reward(completion, ground_truth, alpha=0.8):
    return alpha * accuracy_reward(completion, ground_truth)          + (1 - alpha) * format_reward(completion)

from datasets import Dataset, load_dataset

def make_reasoning_prompt(problem):
    return f"{SYSTEM_PROMPT}

Problem: {problem}

Solution:"

def prepare_dataset(raw_examples):
    return Dataset.from_list([
        {"prompt": make_reasoning_prompt(ex["problem"]), "answer": ex["answer"]}
        for ex in raw_examples
    ])

math_data = load_dataset("lighteval/MATH", split="train")
reasoning_dataset = prepare_dataset([
    {"problem": ex["problem"], "answer": ex["answer"]}
    for ex in math_data
    if ex["level"] in ("Level 4", "Level 5")
])

# Wrong: reward shaping with outcome-based partial credit
def wrong_reward(completion, ground_truth):
    # Giving credit for "close" answers leaks ground truth signal into training
    try:
        pred = float(extract_answer(completion) or "nan")
        truth = float(ground_truth)
        return 1.0 - min(abs(pred - truth) / (abs(truth) + 1e-8), 1.0)
    except ValueError:
        return 0.0

# Right: binary correctness only (after normalisation)
def correct_reward(completion, ground_truth):
    ans = extract_answer(completion)
    if ans is None:
        return 0.0
    return 1.0 if normalize(ans) == normalize(ground_truth) else 0.0
